import React, { useState, useEffect } from 'react';
import { supabase } from './supabaseClient';

export default function Dashboard({ user }) {
  const [healthData, setHealthData] = useState({});
  const [showUpload, setShowUpload] = useState(false);
  const [labReport, setLabReport] = useState(null);

  // Fetch user profile or health data
  useEffect(() => {
    // Fetch data if needed
  }, []);

  const handleUpload = async () => {
    if (labReport) {
      const { data, error } = await supabase.storage
        .from('lab-reports')
        .upload(`${user.id}/${labReport.name}`, labReport);
      if (error) console.log(error);
      else alert('Upload successful');
    }
  };

  const handleFileChange = (e) => {
    setLabReport(e.target.files[0]);
  };

  return (
    <div style={{ padding: '2rem' }}>
      <h2>Clinical Overview</h2>
      {/* Example of health data display */}
      <div>
        <p>Blood Pressure: 129/80 mmHg</p>
        <p>Sugar: 130 mg/dL</p>
        {/* Add more health data as needed */}
      </div>

      {/* Button to show data upload form */}
      <button onClick={() => setShowUpload(true)}>Upload Health Data</button>

      {showUpload && (
        <div style={{ border: '1px solid #ccc', padding: '1rem', marginTop: '1rem' }}>
          <h3>Upload Lab Report</h3>
          <input type="file" onChange={handleFileChange} />
          <button onClick={handleUpload}>Upload</button>
        </div>
      )}
    </div>
  );
}
